const wpI18n = window.wp.i18n;

export function __(text: string, domain = "breakdance") {
  return wpI18n.__(text, domain);
}

export function _x(text: string, context: string, domain = "breakdance") {
  return wpI18n._x(text, context, domain);
}

export function _nx(
  single: string,
  plural: string,
  number: number,
  context: string,
  domain = "breakdance"
) {
  return wpI18n._nx(single, plural, number, context, domain);
}

// _doc is non-standard, but it allows us to easily pass explanations in vue templates for the extract tool
// eslint-disable-next-line @typescript-eslint/no-unused-vars
export function _doc(text: string, _explanation: string) {
  return wpI18n.__(text, "breakdance");
}

// _xdoc combines _x and _doc - it uses context for translation and explanation for the extract tool
// eslint-disable-next-line @typescript-eslint/no-unused-vars
export function _xdoc(
  text: string,
  context: string,
  _explanation: string,
  domain = "breakdance"
) {
  return wpI18n._x(text, context, domain);
}

export const sprintf = wpI18n.sprintf;

export function detectI18nLocale(): string | undefined {
  if (typeof document === "undefined") return undefined;
  const lang = document.documentElement.getAttribute("lang");
  if (!lang) return "en";
  try {
    return new Intl.Locale(lang).toString();
  } catch {
    return lang;
  }
}

export function i18nFormatList(items: string[]) {
  if (!Array.isArray(items) || items.length === 0) return "";

  const loc = detectI18nLocale();

  const formatter = new Intl.ListFormat(loc, {
    style: "long",
    type: "conjunction"
  });

  return formatter.format(items);
}
